--  DDL for View V_CHEFLIVREUR_LIVRAISONS
--------------------------------------------------------

  CREATE OR REPLACE FORCE VIEW "PROJET_SGBD"."V_CHEFLIVREUR_LIVRAISONS" ("LIVREUR", "NOCDE", "DATELIV", "VILLECLT", "ADRCLT") AS 
  SELECT l.LIVREUR, l.NOCDE, l.DATELIV, cl.VILLECLT, cl.ADRCLT
     FROM PROJET_SGBD.LivraisonCom l
     JOIN PROJET_SGBD.Commandes c ON l.NOCDE = c.NOCDE
     JOIN PROJET_SGBD.Clients cl ON c.NOCLT = cl.NOCLT
  GRANT SELECT ON "PROJET_SGBD"."V_CHEFLIVREUR_LIVRAISONS" TO "AHMED"
