--  DDL for Trigger TRG_ALERTE_TEL_FORMAT
--------------------------------------------------------

  CREATE OR REPLACE TRIGGER "PROJET_SGBD"."TRG_ALERTE_TEL_FORMAT" 
BEFORE INSERT OR UPDATE ON Personnel 
FOR EACH ROW
BEGIN
    IF :NEW.telpers IS NOT NULL AND (:NEW.telpers < 10000000 OR :NEW.telpers > 99999999) THEN
        RAISE_APPLICATION_ERROR(-20101, 'ALERTE : Le format du téléphone est invalide (8 chiffres requis).');
    END IF;
END;
ALTER TRIGGER "PROJET_SGBD"."TRG_ALERTE_TEL_FORMAT" ENABLE
