--  DDL for Trigger TRG_ARCHIVE_ANNULATION
--------------------------------------------------------

  CREATE OR REPLACE TRIGGER "PROJET_SGBD"."TRG_ARCHIVE_ANNULATION" 
AFTER UPDATE OF etatcde ON Commandes
FOR EACH ROW
 WHEN (NEW.etatcde = 'AN') DECLARE
    v_montant NUMBER;
    v_cp NUMBER; 
    v_nbrart NUMBER;
BEGIN

    SELECT COUNT(*), NVL(SUM(l.qtecde * a.PRIX), 0)
    INTO v_nbrart, v_montant
    FROM LigCdes l
    JOIN Articles a ON l.refart = a.refart
    WHERE l.nocde = :NEW.nocde;


    SELECT CODE_POSTAL INTO v_cp
    FROM Clients
    WHERE noclt = :NEW.noclt;


        nocde, 
        numclt, 
        nbrart, 
        montantc, 
        datecde, 
        dateAnnulation, 
        CODE_POSTAL,  
        AvantLiv
    ) VALUES (
        :NEW.nocde, 
        :NEW.noclt, 
        v_nbrart, 
        v_montant, 
        :OLD.datecde, 
        SYSDATE, 
        v_cp, 
        'TRUE'
    );
END;
ALTER TRIGGER "PROJET_SGBD"."TRG_ARCHIVE_ANNULATION" ENABLE
--------------------------------------------------------
--  DDL for Trigger TRG_CONTROLE_HORAIRE_LIV
--------------------------------------------------------

  CREATE OR REPLACE TRIGGER "PROJET_SGBD"."TRG_CONTROLE_HORAIRE_LIV" 
BEFORE UPDATE ON LivraisonCom
FOR EACH ROW
DECLARE
    v_heure NUMBER;
BEGIN
    -- On récupère l'heure actuelle (format 24h)
    v_heure := TO_NUMBER(TO_CHAR(SYSDATE, 'HH24'));

    -- On change la condition de 14 à 18
    IF v_heure >= 18 THEN
        RAISE_APPLICATION_ERROR(-20103, 'ALERTE : Modification interdite après 18h00.');
    END IF;
END;
