--  DDL for Package Body PKG_COMMANDES
--------------------------------------------------------

  CREATE OR REPLACE PACKAGE BODY "PROJET_SGBD"."PKG_COMMANDES" AS

    -- ... (AjouterCommande, AjouterLigne, ModifierEtat, Annuler restent inchangés) ...
    -- Je remets juste le début pour que vous ayez tout le bloc si besoin, 
    -- mais le changement important est à la fin (ChercherCommande).

    PROCEDURE AjouterCommande(p_noclt IN Commandes.noclt%TYPE, p_new_nocde OUT Commandes.nocde%TYPE) IS
    BEGIN
        COMMIT;
    EXCEPTION WHEN OTHERS THEN ROLLBACK; PKG_MESSAGES.LEVER_ERREUR(PKG_MESSAGES.ERR_GENERIQUE_CODE, 'Erreur Ajout : ' || SQLERRM);
    END AjouterCommande;

    PROCEDURE AjouterLigneCommande(p_nocde IN LigCdes.nocde%TYPE, p_refart IN LigCdes.refart%TYPE, p_qte IN LigCdes.qtecde%TYPE) IS
    BEGIN
        COMMIT;
    EXCEPTION WHEN OTHERS THEN ROLLBACK; PKG_MESSAGES.LEVER_ERREUR(PKG_MESSAGES.ERR_GENERIQUE_CODE, 'Erreur Ligne : ' || SQLERRM);
    END AjouterLigneCommande;

    PROCEDURE ModifierEtatCommande(p_nocde IN Commandes.nocde%TYPE, p_nouv_etat IN Commandes.etatcde%TYPE) IS
        v_etat_actuel Commandes.etatcde%TYPE; e_check_constraint EXCEPTION; PRAGMA EXCEPTION_INIT(e_check_constraint, -2290);
    BEGIN
        SELECT etatcde INTO v_etat_actuel FROM Commandes WHERE nocde = p_nocde;
        IF (v_etat_actuel = 'EC' AND p_nouv_etat IN ('PR', 'AN')) OR (v_etat_actuel = 'PR' AND p_nouv_etat IN ('LI', 'AN', 'AL')) OR (v_etat_actuel = 'LI' AND p_nouv_etat = 'SO') THEN
            UPDATE Commandes SET etatcde = p_nouv_etat WHERE nocde = p_nocde; COMMIT;
        ELSE
            IF v_etat_actuel = 'EC' AND p_nouv_etat = 'AL' THEN PKG_MESSAGES.LEVER_ERREUR(PKG_MESSAGES.ERR_TRANSITION_CODE, 'Impossible EC -> AL. Il faut passer par PR.');
            ELSIF v_etat_actuel = 'EC' AND p_nouv_etat = 'LI' THEN PKG_MESSAGES.LEVER_ERREUR(PKG_MESSAGES.ERR_TRANSITION_CODE, 'Impossible EC -> LI. Il faut passer par PR.');
            ELSE PKG_MESSAGES.LEVER_ERREUR(PKG_MESSAGES.ERR_TRANSITION_CODE, 'Transition interdite : ' || v_etat_actuel || ' -> ' || p_nouv_etat); END IF;
        END IF;
    EXCEPTION WHEN NO_DATA_FOUND THEN PKG_MESSAGES.LEVER_ERREUR(PKG_MESSAGES.ERR_CMD_INEXISTANTE_CODE, PKG_MESSAGES.ERR_CMD_INEXISTANTE_MSG);
    WHEN e_check_constraint THEN ROLLBACK; PKG_MESSAGES.LEVER_ERREUR(PKG_MESSAGES.ERR_CONTRAINTE_CHECK_CODE, 'Etat interdit.');
    WHEN OTHERS THEN ROLLBACK; IF SQLCODE BETWEEN -20999 AND -20000 THEN RAISE; ELSE PKG_MESSAGES.LEVER_ERREUR(PKG_MESSAGES.ERR_GENERIQUE_CODE, 'Erreur Modif : ' || SQLERRM); END IF;
    END ModifierEtatCommande;

    PROCEDURE AnnulerCommande(p_nocde IN Commandes.nocde%TYPE) IS
        v_etat_actuel Commandes.etatcde%TYPE;
    BEGIN
        SELECT etatcde INTO v_etat_actuel FROM Commandes WHERE nocde = p_nocde;
        IF v_etat_actuel NOT IN ('EC', 'PR') THEN PKG_MESSAGES.LEVER_ERREUR(PKG_MESSAGES.ERR_ANNUL_IMPOSSIBLE_CODE, 'Annulation impossible (déjà Livrée/Soldée).'); END IF;
        UPDATE Commandes SET etatcde = 'AN' WHERE nocde = p_nocde; COMMIT;
    EXCEPTION WHEN NO_DATA_FOUND THEN PKG_MESSAGES.LEVER_ERREUR(PKG_MESSAGES.ERR_CMD_INEXISTANTE_CODE, PKG_MESSAGES.ERR_CMD_INEXISTANTE_MSG);
    WHEN OTHERS THEN ROLLBACK; IF SQLCODE BETWEEN -20999 AND -20000 THEN RAISE; ELSE PKG_MESSAGES.LEVER_ERREUR(PKG_MESSAGES.ERR_GENERIQUE_CODE, 'Erreur Annulation : ' || SQLERRM); END IF;
    END AnnulerCommande;

    -- =========================================================================
    -- CHERCHER COMMANDE (CORRIGÉ AVEC MONTANT ET NOM CLIENT)
    -- =========================================================================
   FUNCTION ChercherCommande(
        p_nocde IN NUMBER DEFAULT NULL,
        p_noclt IN NUMBER DEFAULT NULL,
        p_date IN DATE DEFAULT NULL
    ) RETURN SYS_REFCURSOR IS
        c_result SYS_REFCURSOR;
    BEGIN
        OPEN c_result FOR
            SELECT 
                c.NOCDE, 
                c.NOCLT, 
                c.DATECDE, 
                c.ETATCDE,
                cl.NOMCLT,  -- On ajoute le nom du client
                NVL((SELECT SUM(l.QTECDE * a.PRIX)  -- CORRECTION ICI : a.PRIXV au lieu de a.PRIX
                     FROM LIGCDES l 
                     JOIN ARTICLES a ON l.REFART = a.REFART 
                     WHERE l.NOCDE = c.NOCDE), 0) AS MONTANT 
            FROM Commandes c
            JOIN Clients cl ON c.NOCLT = cl.NOCLT
            WHERE (p_nocde IS NULL OR c.nocde = p_nocde)
            AND   (p_noclt IS NULL OR c.noclt = p_noclt)
            AND   (p_date IS NULL OR TRUNC(c.datecde) = TRUNC(p_date))
            ORDER BY c.nocde DESC;
        RETURN c_result; 
        END ChercherCommande;
END PKG_Commandes;
--------------------------------------------------------
--  DDL for Package Body PKG_LIVRAISONS
--------------------------------------------------------

  CREATE OR REPLACE PACKAGE BODY "PROJET_SGBD"."PKG_LIVRAISONS" AS

  --------------------------------------------------------------------
  -- 1) AJOUTER LIVRAISON
  --    - La commande doit être en état 'PR'
  --    - Le livreur ne doit pas dépasser CLIMITE_LIVRAISONS
  --      commandes par jour et par ville (code postal)
  --------------------------------------------------------------------
  PROCEDURE AjouterLivraison(
    pnocde    IN NUMBER,
    pdateliv  IN DATE,
    plivreur  IN NUMBER,
    pmodepay  IN VARCHAR2
  ) IS
    v_etatcde   Commandes.etatcde%TYPE;
    v_cp        Clients.code_postal%TYPE;
    v_nb_livr   NUMBER;
  BEGIN
    -- Vérifier que la commande existe et est PRÊTE
    SELECT c.etatcde, cl.code_postal
      INTO v_etatcde, v_cp
      FROM Commandes c
      JOIN Clients   cl ON cl.noclt = c.noclt
     WHERE c.nocde = pnocde;

    IF v_etatcde <> 'PR' THEN
      -- Ici tu peux appeler PKG_Messages au lieu de raise_application_error
      RAISE_APPLICATION_ERROR(
        -20040,
        'La commande ' || pnocde || ' n''est pas prête à la livraison.'
      );
    END IF;

    -- Vérifier la limite 15 livraisons / jour / ville / livreur
    SELECT COUNT(*)
      INTO v_nb_livr
      FROM LivraisonCom l
      JOIN Commandes   c2 ON c2.nocde = l.nocde
      JOIN Clients     cl2 ON cl2.noclt = c2.noclt
     WHERE l.livreur = plivreur
       AND TRUNC(l.dateliv) = TRUNC(pdateliv)
       AND cl2.code_postal = v_cp;

    IF v_nb_livr >= CLIMITE_LIVRAISONS THEN
      RAISE_APPLICATION_ERROR(
        -20041,
        'Le livreur ' || plivreur ||
        ' a déjà atteint la limite de ' || CLIMITE_LIVRAISONS ||
        ' livraisons pour ce jour et cette ville.'
      );
    END IF;

    -- Insérer la livraison
    VALUES (pnocde, pdateliv, plivreur, pmodepay, 'EC');  -- PL = planifiée
  END AjouterLivraison;

  --------------------------------------------------------------------
  -- 2) CONTRÔLE HORAIRE POUR MODIFICATION / AJOUT
  --------------------------------------------------------------------
  PROCEDURE Verifier_Horaire(p_date_liv IN DATE) IS
    v_now    DATE := SYSDATE;
    v_jour   DATE := TRUNC(v_now);
    v_heure  NUMBER := TO_NUMBER(TO_CHAR(v_now, 'HH24'));
  BEGIN
    IF TRUNC(p_date_liv) = v_jour THEN
      -- Livraison du jour
      IF TO_NUMBER(TO_CHAR(p_date_liv, 'HH24')) < 12 THEN
        -- Livraison du matin → limite 9h
        IF v_heure >= 9 THEN
          RAISE_APPLICATION_ERROR(
            -20042,
            'La mise à jour pour les livraisons du matin doit se faire avant 9h.'
          );
        END IF;
      ELSE
        -- Livraison de l'après-midi → limite 14h
        IF v_heure >= 14 THEN
          RAISE_APPLICATION_ERROR(
            -20043,
            'La mise à jour pour les livraisons de l''après-midi doit se faire avant 14h.'
          );
        END IF;
      END IF;
    END IF;
  END Verifier_Horaire;

  --------------------------------------------------------------------
  -- 3) MODIFIER LIVRAISON (date et/ou livreur)
  --------------------------------------------------------------------
  PROCEDURE ModifierLivraison(
    pnocde    IN NUMBER,
    pnouvdate IN DATE   DEFAULT NULL,
    pnouvlivr IN NUMBER DEFAULT NULL
  ) IS
    v_old_date DATE;
  BEGIN
    SELECT dateliv
      INTO v_old_date
      FROM LivraisonCom
     WHERE nocde = pnocde;

    -- Contrôle horaire sur la nouvelle date si fournie, sinon sur l'ancienne
    IF pnouvdate IS NOT NULL THEN
      Verifier_Horaire(pnouvdate);
    ELSE
      Verifier_Horaire(v_old_date);
    END IF;

    UPDATE LivraisonCom
       SET dateliv = COALESCE(pnouvdate, dateliv),
           livreur = COALESCE(pnouvlivr, livreur)
     WHERE nocde = pnocde;
  END ModifierLivraison;

  --------------------------------------------------------------------
  -- 4) SUPPRIMER LIVRAISON
  --    - Annule la livraison
  --    - Met la commande à AN (annulée avant livraison)
  --    - Insère dans HCommandesAnnulees avec AVANTLIV = 'TRUE'
  --------------------------------------------------------------------
  PROCEDURE SupprimerLivraison(pnocde IN NUMBER) IS
    v_numcli     Commandes.noclt%TYPE;
    v_datecde    Commandes.datecde%TYPE;
    v_codepostal Clients.code_postal%TYPE;
    v_nbrart     NUMBER;
    v_montantc   NUMBER;
  BEGIN
    -- Récupérer infos de base commande + client
    SELECT c.noclt, c.datecde, cl.code_postal
      INTO v_numcli, v_datecde, v_codepostal
      FROM Commandes c
      JOIN Clients   cl ON cl.noclt = c.noclt
     WHERE c.nocde = pnocde;

    -- Calcul simple : nombre de lignes + montant total
    SELECT COUNT(*),
           SUM(lc.qtecde * a.prix)
      INTO v_nbrart, v_montantc
      FROM LigCdes lc
      JOIN Articles a ON a.refart = lc.refart
     WHERE lc.nocde = pnocde;

    -- Supprimer la livraison
    DELETE FROM LivraisonCom
     WHERE nocde = pnocde;

    -- Mettre la commande en AN
    UPDATE Commandes
       SET etatcde = 'AN'
     WHERE nocde = pnocde;

    -- Historisation (toutes les colonnes principales + AVANTLIV)
  END SupprimerLivraison;

  --------------------------------------------------------------------
  -- 5) CHERCHER LIVRAISON (par commande, livreur, ville et/ou date)
  --------------------------------------------------------------------
  FUNCTION ChercherLivraison(
    pnocde   IN NUMBER   DEFAULT NULL,
    plivreur IN NUMBER   DEFAULT NULL,
    pville   IN VARCHAR2 DEFAULT NULL,
    pdate    IN DATE     DEFAULT NULL
  ) RETURN SYS_REFCURSOR IS
    v_cur SYS_REFCURSOR;
  BEGIN
    OPEN v_cur FOR
      SELECT
        l.nocde,
        l.dateliv,
        l.livreur,
        l.modepay,
        l.etatliv  AS etat,
        c.villeclt
      FROM LivraisonCom l
      JOIN Commandes   co ON co.nocde = l.nocde
      JOIN Clients     c  ON c.noclt  = co.noclt
      WHERE (pnocde   IS NULL OR l.nocde          = pnocde)
        AND (plivreur IS NULL OR l.livreur        = plivreur)
        AND (pdate    IS NULL OR TRUNC(l.dateliv) = TRUNC(pdate))
        AND (pville   IS NULL OR UPPER(c.villeclt) LIKE '%' || UPPER(pville) || '%')
      ORDER BY l.nocde;

    RETURN v_cur;
  END ChercherLivraison;

  --------------------------------------------------------------------
  -- 6) LISTER LES COMMANDES PRÊTES A LA LIVRAISON
  --------------------------------------------------------------------
  FUNCTION ListerCommandesPretes(
    pnocde IN NUMBER   DEFAULT NULL,
    pville IN VARCHAR2 DEFAULT NULL,
    pdate  IN DATE     DEFAULT NULL
  ) RETURN SYS_REFCURSOR IS
    v_cur SYS_REFCURSOR;
  BEGIN
    OPEN v_cur FOR
      SELECT
        c.nocde,
        c.datecde,
        c.etatcde,
        cl.nomclt,
        cl.villeclt
      FROM Commandes c
      JOIN Clients   cl ON cl.noclt = c.noclt
      WHERE c.etatcde = 'PR'
        AND (pnocde IS NULL OR c.nocde           = pnocde)
        AND (pdate  IS NULL OR TRUNC(c.datecde)  = TRUNC(pdate))
        AND (pville IS NULL OR UPPER(cl.villeclt) LIKE '%' || UPPER(pville) || '%')
      ORDER BY c.nocde;

    RETURN v_cur;
  END ListerCommandesPretes;

END PKG_Livraisons;
