--  DDL for Package Body PKG_PRIVILEGES
--------------------------------------------------------

  CREATE OR REPLACE PACKAGE BODY "PROJET_SGBD"."PKG_PRIVILEGES" AS
 
  -- =========================================================================
  -- 1. CRÉATION DES VUES
  -- =========================================================================
  PROCEDURE Creer_Schemas_Externes IS
  BEGIN
    EXECUTE IMMEDIATE '
      CREATE OR REPLACE VIEW V_Magasinier_Commandes AS
      SELECT NOCDE, NOCLT, DATECDE, ETATCDE FROM PROJET_SGBD.Commandes';

    EXECUTE IMMEDIATE '
      CREATE OR REPLACE VIEW V_Magasinier_Articles AS
      SELECT REFART, DESIGNATION, CATEGORIE, QTESTK FROM PROJET_SGBD.Articles';

    EXECUTE IMMEDIATE '
     CREATE OR REPLACE VIEW V_ChefLivreur_Livraisons AS
     SELECT l.LIVREUR, l.NOCDE, l.DATELIV, cl.VILLECLT, cl.ADRCLT
     FROM PROJET_SGBD.LivraisonCom l
     JOIN PROJET_SGBD.Commandes c ON l.NOCDE = c.NOCDE
     JOIN PROJET_SGBD.Clients cl ON c.NOCLT = cl.NOCLT';

    EXECUTE IMMEDIATE '
      CREATE OR REPLACE VIEW V_Livreurs AS
      SELECT IDPERS, NOMPERS, PRENOMPERS, LOGIN, CODEPOSTE
      FROM PROJET_SGBD.Personnel WHERE CODEPOSTE = 4';

    EXECUTE IMMEDIATE '
      CREATE OR REPLACE VIEW V_Mon_Profil AS
      SELECT LOGIN, CODEPOSTE, NOMPERS, PRENOMPERS
      FROM PROJET_SGBD.Personnel WHERE UPPER(LOGIN) = USER';

    DBMS_OUTPUT.PUT_LINE('✅ Vues créées avec succès.');
  EXCEPTION
    WHEN OTHERS THEN
      DBMS_OUTPUT.PUT_LINE('⚠️ Info création vues : ' || SQLERRM);
  END Creer_Schemas_Externes;

  -- =========================================================================
  -- 2. CRÉATION / MAJ USER ORACLE
  -- =========================================================================
  PROCEDURE Creer_Compte_Oracle(p_login IN VARCHAR2, p_password IN VARCHAR2) IS
    v_exist NUMBER;
    v_login VARCHAR2(30) := UPPER(TRIM(p_login));
  BEGIN
    SELECT COUNT(*) INTO v_exist FROM ALL_USERS WHERE USERNAME = v_login;
    IF v_exist = 0 THEN
      EXECUTE IMMEDIATE 'CREATE USER ' || v_login || ' IDENTIFIED BY ' || TRIM(p_password);
      EXECUTE IMMEDIATE 'GRANT CREATE SESSION TO ' || v_login;
    ELSE
      EXECUTE IMMEDIATE 'ALTER USER ' || v_login || ' IDENTIFIED BY ' || TRIM(p_password);
    END IF;
  END Creer_Compte_Oracle;

  -- =========================================================================
  -- 3. ATTRIBUTION ROLES + GRANTS
  -- =========================================================================
  PROCEDURE Attribuer_Role(p_login IN VARCHAR2, p_role IN VARCHAR2, p_password IN VARCHAR2) IS
    v_login VARCHAR2(30) := UPPER(TRIM(p_login));
  BEGIN
    Creer_Compte_Oracle(p_login, p_password);

    IF UPPER(p_role) = 'CHEFLIVREUR' THEN
      EXECUTE IMMEDIATE 'GRANT SELECT ON PROJET_SGBD.LivraisonCom TO ' || v_login;
      EXECUTE IMMEDIATE 'GRANT SELECT ON PROJET_SGBD.Commandes TO ' || v_login;
      EXECUTE IMMEDIATE 'GRANT SELECT ON PROJET_SGBD.Clients TO ' || v_login;
      EXECUTE IMMEDIATE 'GRANT SELECT ON PROJET_SGBD.Personnel TO ' || v_login;
      EXECUTE IMMEDIATE 'GRANT SELECT ON PROJET_SGBD.LigCdes TO ' || v_login;
      EXECUTE IMMEDIATE 'GRANT SELECT ON PROJET_SGBD.Articles TO ' || v_login;

      EXECUTE IMMEDIATE 'GRANT SELECT ON PROJET_SGBD.V_ChefLivreur_Livraisons TO ' || v_login;
      EXECUTE IMMEDIATE 'GRANT SELECT ON PROJET_SGBD.V_Mon_Profil TO ' || v_login;
      EXECUTE IMMEDIATE 'GRANT SELECT ON PROJET_SGBD.V_Livreurs TO ' || v_login;

      EXECUTE IMMEDIATE 'CREATE OR REPLACE SYNONYM ' || v_login || '.LivraisonCom FOR PROJET_SGBD.LivraisonCom';
      EXECUTE IMMEDIATE 'CREATE OR REPLACE SYNONYM ' || v_login || '.Commandes FOR PROJET_SGBD.Commandes';
      EXECUTE IMMEDIATE 'CREATE OR REPLACE SYNONYM ' || v_login || '.Clients FOR PROJET_SGBD.Clients';
      EXECUTE IMMEDIATE 'CREATE OR REPLACE SYNONYM ' || v_login || '.Personnel FOR PROJET_SGBD.Personnel';
      EXECUTE IMMEDIATE 'CREATE OR REPLACE SYNONYM ' || v_login || '.LigCdes FOR PROJET_SGBD.LigCdes';
      EXECUTE IMMEDIATE 'CREATE OR REPLACE SYNONYM ' || v_login || '.Articles FOR PROJET_SGBD.Articles';
      EXECUTE IMMEDIATE 'CREATE OR REPLACE SYNONYM ' || v_login || '.V_ChefLivreur_Livraisons FOR PROJET_SGBD.V_ChefLivreur_Livraisons';
      EXECUTE IMMEDIATE 'CREATE OR REPLACE SYNONYM ' || v_login || '.V_Mon_Profil FOR PROJET_SGBD.V_Mon_Profil';
      EXECUTE IMMEDIATE 'CREATE OR REPLACE SYNONYM ' || v_login || '.V_Livreurs FOR PROJET_SGBD.V_Livreurs';

      DBMS_OUTPUT.PUT_LINE('✅ Rôle CHEFLIVREUR attribué à ' || v_login);

    ELSIF UPPER(p_role) = 'LIVREUR' THEN
      EXECUTE IMMEDIATE 'GRANT SELECT ON PROJET_SGBD.LivraisonCom TO ' || v_login;
      EXECUTE IMMEDIATE 'GRANT SELECT ON PROJET_SGBD.Commandes TO ' || v_login;
      EXECUTE IMMEDIATE 'GRANT SELECT ON PROJET_SGBD.Clients TO ' || v_login;
      EXECUTE IMMEDIATE 'GRANT SELECT ON PROJET_SGBD.LigCdes TO ' || v_login;
      EXECUTE IMMEDIATE 'GRANT SELECT ON PROJET_SGBD.Articles TO ' || v_login;
      EXECUTE IMMEDIATE 'GRANT SELECT ON PROJET_SGBD.V_Mon_Profil TO ' || v_login;

      EXECUTE IMMEDIATE 'GRANT UPDATE (ETATLIV, MODEPAY) ON PROJET_SGBD.LivraisonCom TO ' || v_login;
      EXECUTE IMMEDIATE 'GRANT UPDATE (ETATCDE) ON PROJET_SGBD.Commandes TO ' || v_login;

      EXECUTE IMMEDIATE 'CREATE OR REPLACE SYNONYM ' || v_login || '.LivraisonCom FOR PROJET_SGBD.LivraisonCom';
      EXECUTE IMMEDIATE 'CREATE OR REPLACE SYNONYM ' || v_login || '.Commandes FOR PROJET_SGBD.Commandes';
      EXECUTE IMMEDIATE 'CREATE OR REPLACE SYNONYM ' || v_login || '.Clients FOR PROJET_SGBD.Clients';
      EXECUTE IMMEDIATE 'CREATE OR REPLACE SYNONYM ' || v_login || '.LigCdes FOR PROJET_SGBD.LigCdes';
      EXECUTE IMMEDIATE 'CREATE OR REPLACE SYNONYM ' || v_login || '.Articles FOR PROJET_SGBD.Articles';
      EXECUTE IMMEDIATE 'CREATE OR REPLACE SYNONYM ' || v_login || '.V_Mon_Profil FOR PROJET_SGBD.V_Mon_Profil';

      DBMS_OUTPUT.PUT_LINE('✅ Rôle LIVREUR attribué à ' || v_login);

    END IF;
  END Attribuer_Role;
END PKG_PRIVILEGES;
