  CREATE OR REPLACE PACKAGE BODY "PROJET_SGBD"."PKG_UTILISATEURS" AS

    PROCEDURE Ajouter_Utilisateur(
        p_nom        IN Personnel.nompers%TYPE,
        p_prenom     IN Personnel.prenompers%TYPE,
        p_adr        IN Personnel.adrpers%TYPE,
        p_ville      IN Personnel.villepers%TYPE,
        p_tel        IN Personnel.telpers%TYPE,
        p_embauche   IN Personnel.d_embauche%TYPE,
        p_login      IN Personnel.Login%TYPE,
        p_mdp        IN Personnel.motP%TYPE,
        p_codeposte  IN Personnel.codeposte%TYPE
    ) AS
    BEGIN
            idpers,
            nompers, prenompers, adrpers, villepers, telpers,
            d_embauche, Login, motP, codeposte
        ) VALUES (
            SEQ_Personnel.NEXTVAL,
            p_nom, p_prenom, p_adr, p_ville, p_tel,
            p_embauche, p_login, p_mdp, p_codeposte
        );
        COMMIT;
    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            RAISE;
    END Ajouter_Utilisateur;

    PROCEDURE Modifier_Utilisateur(
        p_idpers     IN Personnel.idpers%TYPE,
        p_nom        IN Personnel.nompers%TYPE,
        p_prenom     IN Personnel.prenompers%TYPE,
        p_adr        IN Personnel.adrpers%TYPE,
        p_ville      IN Personnel.villepers%TYPE,
        p_tel        IN Personnel.telpers%TYPE,
        p_codeposte  IN Personnel.codeposte%TYPE
    ) AS
    BEGIN
        UPDATE Personnel
        SET nompers   = p_nom,
            prenompers = p_prenom,
            adrpers    = p_adr,
            villepers  = p_ville,
            telpers    = p_tel,
            codeposte  = p_codeposte
        WHERE idpers = p_idpers;

        IF SQL%ROWCOUNT = 0 THEN
            RAISE_APPLICATION_ERROR(-20001, 'Utilisateur non trouvé');
        END IF;

        COMMIT;
    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            RAISE;
    END Modifier_Utilisateur;

    PROCEDURE Supprimer_Utilisateur(
        p_idpers IN Personnel.idpers%TYPE
    ) AS
    BEGIN
        DELETE FROM Personnel
        WHERE idpers = p_idpers;

        IF SQL%ROWCOUNT = 0 THEN
            RAISE_APPLICATION_ERROR(-20002, 'Utilisateur non trouvé');
        END IF;

        COMMIT;
    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            RAISE;
    END Supprimer_Utilisateur;

    FUNCTION Chercher_Utilisateur(
        p_critere VARCHAR2
    ) RETURN SYS_REFCURSOR AS
        v_cursor SYS_REFCURSOR;
    BEGIN
        OPEN v_cursor FOR
            SELECT *
            FROM Personnel
            WHERE UPPER(nompers)    LIKE '%' || UPPER(p_critere) || '%'
               OR UPPER(prenompers) LIKE '%' || UPPER(p_critere) || '%'
               OR UPPER(Login)      LIKE '%' || UPPER(p_critere) || '%'
               OR TO_CHAR(idpers)   LIKE '%' || p_critere || '%';

        RETURN v_cursor;
    EXCEPTION
        WHEN OTHERS THEN
            IF v_cursor%ISOPEN THEN
                CLOSE v_cursor;
            END IF;
            RAISE;
    END Chercher_Utilisateur;

    FUNCTION GET_CODEPOSTE_BY_LOGIN(
        p_login IN Personnel.Login%TYPE
    ) RETURN Personnel.codeposte%TYPE IS
        v_code Personnel.codeposte%TYPE;
    BEGIN
        SELECT codeposte
        INTO v_code
        FROM Personnel
        WHERE Login = p_login;

        RETURN v_code;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            RETURN NULL;
    END GET_CODEPOSTE_BY_LOGIN;

END PKG_Utilisateurs;
--------------------------------------------------------
--  DDL for Function UTL_CALCULER_MONTANT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "PROJET_SGBD"."UTL_CALCULER_MONTANT" (p_nocde NUMBER) RETURN NUMBER IS
    v_total NUMBER := 0;
BEGIN
    SELECT NVL(SUM(l.qtecde * a.prix), 0)
    INTO v_total
    FROM LigCdes l
    JOIN Articles a ON l.refart = a.refart
    WHERE l.nocde = p_nocde;

    RETURN v_total;
END;
CREATE OR REPLACE FUNCTION Utl_Compter_Livraisons_Jour(
    p_livreur VARCHAR2, 
    p_date DATE,
    p_ville VARCHAR2
) RETURN NUMBER IS
    v_count NUMBER;
BEGIN
    SELECT COUNT(*)
    INTO v_count
    FROM LivraisonCom l
    JOIN Commandes c ON l.nocde = c.nocde
    JOIN Clients cl ON c.noclt = cl.noclt
    WHERE l.livreur = p_livreur
      AND TRUNC(l.dateliv) = TRUNC(p_date)
      AND cl.villeclt = p_ville; 

    RETURN v_count;
END;
